// Rule: CRITICAL — Eliminate Request Waterfalls
// ❌ Sequential (waterfall)
async function Page() {
  const user = await getUser();          // waits
  const posts = await getPosts(user.id); // waits again
}

// ✅ Parallel (correct)
async function Page() {
  const [user, posts] = await Promise.all([
    getUser(),
    getPosts(),
  ]);
}

