// ✅ Fix applied:
async function ProductsPage() {
  const [categories, products] = await Promise.all([
    getCategories(),
    getProducts(),
  ]);
  return (
    <Suspense fallback={<ProductListSkeleton />}>
      <ProductList products={products} categories={categories} />
    </Suspense>
  );
